import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../services/axios';

const CATEGORIES = ['All', 'Concert', 'Conference', 'Workshop', 'Sports', 'Exhibition', 'Festival', 'Comedy', 'Theatre', 'Other'];

const DEMO_EVENTS = [
  {
    _id: 'demo1', name: 'Neon Night Party', category: 'Festival', price: 799,
    venue: 'Sky Lounge, Mumbai', date: '2026-04-15', time: '20:00',
    availableSeats: 120, totalSeats: 200, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1516450360452-9312f5e86fc7?w=600&q=80'
  },
  {
    _id: 'demo2', name: 'Summer Music Festival', category: 'Concert', price: 1299,
    venue: 'Beach Arena, Goa', date: '2026-05-20', time: '18:00',
    availableSeats: 500, totalSeats: 1000, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=600&q=80'
  },
  {
    _id: 'demo3', name: 'Rooftop DJ Night', category: 'Concert', price: 599,
    venue: 'The Terrace, Bangalore', date: '2026-04-28', time: '21:00',
    availableSeats: 80, totalSeats: 150, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1571266028243-d220c6a9e7b6?w=600&q=80'
  },
  {
    _id: 'demo4', name: 'Startup Conference 2026', category: 'Conference', price: 2499,
    venue: 'Convention Centre, Delhi', date: '2026-06-10', time: '09:00',
    availableSeats: 300, totalSeats: 500, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=600&q=80'
  },
  {
    _id: 'demo5', name: 'Holi Colour Fest', category: 'Festival', price: 399,
    venue: 'Central Park, Hyderabad', date: '2026-03-25', time: '10:00',
    availableSeats: 0, totalSeats: 400, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1615961244836-b6dd9a86eb42?w=600&q=80'
  },
  {
    _id: 'demo6', name: 'Stand-Up Comedy Night', category: 'Comedy', price: 699,
    venue: 'Laugh Factory, Chennai', date: '2026-04-05', time: '19:30',
    availableSeats: 60, totalSeats: 100, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1527224538127-2104bb71c51b?w=600&q=80'
  },
  {
    _id: 'demo7', name: 'Art & Culture Exhibition', category: 'Exhibition', price: 299,
    venue: 'National Gallery, Kolkata', date: '2026-05-01', time: '11:00',
    availableSeats: 200, totalSeats: 300, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1513364776144-60967b0f800f?w=600&q=80'
  },
  {
    _id: 'demo8', name: 'IPL Watch Party 🏏', category: 'Sports', price: 499,
    venue: 'Sports Bar, Pune', date: '2026-04-18', time: '19:00',
    availableSeats: 150, totalSeats: 200, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1531415074968-036ba1b575da?w=600&q=80'
  },
  {
    _id: 'demo9', name: 'Yoga & Wellness Retreat', category: 'Workshop', price: 899,
    venue: 'Sunrise Resort, Rishikesh', date: '2026-05-10', time: '06:00',
    availableSeats: 40, totalSeats: 50, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=600&q=80'
  },
  {
    _id: 'demo10', name: 'Food & Wine Festival', category: 'Festival', price: 1199,
    venue: 'Food Court, Bangalore', date: '2026-06-05', time: '12:00',
    availableSeats: 250, totalSeats: 400, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=600&q=80'
  },
  {
    _id: 'demo11', name: 'Bollywood Dance Night', category: 'Concert', price: 649,
    venue: 'Grand Ballroom, Delhi', date: '2026-04-22', time: '20:30',
    availableSeats: 180, totalSeats: 250, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1504609813442-a8924e83f76e?w=600&q=80'
  },
  {
    _id: 'demo12', name: 'Photography Workshop', category: 'Workshop', price: 1499,
    venue: 'Art Studio, Mumbai', date: '2026-05-15', time: '10:00',
    availableSeats: 25, totalSeats: 30, status: 'upcoming',
    image: 'https://images.unsplash.com/photo-1452587925148-ce544e77e70d?w=600&q=80'
  },
];

function Home() {
  const [events, setEvents] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState('');
  const [locationFilter, setLocationFilter] = useState('');
  const [category, setCategory] = useState('All');
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchEvents(); }, []);

  useEffect(() => {
    let result = events;
    if (search) result = result.filter(e => e.name.toLowerCase().includes(search.toLowerCase()));
    if (locationFilter) result = result.filter(e => e.venue.toLowerCase().includes(locationFilter.toLowerCase()));
    if (category !== 'All') result = result.filter(e => e.category === category);
    setFiltered(result);
  }, [search, locationFilter, category, events]);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      const dbEvents = res.data.events || [];
      // Show DB events if available, otherwise show demo events
      const finalEvents = dbEvents.length > 0 ? dbEvents : DEMO_EVENTS;
      setEvents(finalEvents);
      setFiltered(finalEvents);
    } catch {
      // If API fails, show demo events
      setEvents(DEMO_EVENTS);
      setFiltered(DEMO_EVENTS);
    } finally { setLoading(false); }
  };

  const isDemo = (id) => String(id).startsWith('demo');

  return (
    <div style={{ minHeight: '100vh', background: '#fdf6f3', fontFamily: "'DM Sans', sans-serif" }}>

      {/* HERO */}
      <section style={{ background: 'linear-gradient(135deg, #2d1f1f 0%, #4a2f2f 50%, #3d2525 100%)', padding: '5rem 2rem', position: 'relative', overflow: 'hidden' }}>
        <div style={{ position: 'absolute', top: '-80px', right: '10%', width: '300px', height: '300px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(201,169,154,0.2) 0%, transparent 70%)', pointerEvents: 'none' }} />
        <div style={{ position: 'absolute', bottom: '-60px', left: '5%', width: '250px', height: '250px', borderRadius: '50%', background: 'radial-gradient(circle, rgba(232,196,184,0.15) 0%, transparent 70%)', pointerEvents: 'none' }} />

        <div style={{ maxWidth: '900px', margin: '0 auto', textAlign: 'center', position: 'relative' }}>
          <div style={{ display: 'inline-block', background: 'rgba(201,169,154,0.2)', border: '1px solid rgba(201,169,154,0.3)', borderRadius: '20px', padding: '6px 18px', marginBottom: '1.2rem' }}>
            <span style={{ color: '#e8c4b8', fontSize: '0.78rem', fontWeight: '600', letterSpacing: '2px' }}>✨ DISCOVER AMAZING EXPERIENCES</span>
          </div>
          <h1 style={{ fontSize: 'clamp(2.2rem, 5vw, 3.8rem)', fontWeight: '700', color: 'white', lineHeight: '1.2', marginBottom: '1rem', fontFamily: "'Cormorant Garamond', serif" }}>
            Find & Book Your<br /><span style={{ color: '#e8c4b8' }}>Dream Events</span> 🌸
          </h1>
          <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '1rem', maxWidth: '500px', margin: '0 auto 2.5rem' }}>
            Concerts, festivals, workshops and more — all in one beautiful place.
          </p>

          {/* Search Bar */}
          <div style={{ background: 'rgba(255,255,255,0.08)', backdropFilter: 'blur(20px)', border: '1px solid rgba(201,169,154,0.25)', borderRadius: '18px', padding: '1rem 1.5rem', display: 'flex', gap: '1rem', alignItems: 'center', maxWidth: '700px', margin: '0 auto 2.5rem', flexWrap: 'wrap' }}>
            <div style={{ flex: 1, minWidth: '120px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span>🔍</span>
              <input type="text" placeholder="Search events..." value={search} onChange={e => setSearch(e.target.value)}
                style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: '0.88rem', width: '100%' }} />
            </div>
            <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.15)' }} />
            <div style={{ flex: 1, minWidth: '120px', display: 'flex', alignItems: 'center', gap: '8px' }}>
              <span>📍</span>
              <input type="text" placeholder="City or venue..." value={locationFilter} onChange={e => setLocationFilter(e.target.value)}
                style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: '0.88rem', width: '100%' }} />
            </div>
            <div style={{ width: '1px', height: '24px', background: 'rgba(255,255,255,0.15)' }} />
            <select value={category} onChange={e => setCategory(e.target.value)}
              style={{ background: 'transparent', border: 'none', outline: 'none', color: 'white', fontSize: '0.84rem', cursor: 'pointer' }}>
              {CATEGORIES.map(c => <option key={c} value={c} style={{ background: '#2d1f1f', color: 'white' }}>{c}</option>)}
            </select>
          </div>

          {/* Stats */}
          <div style={{ display: 'flex', justifyContent: 'center', gap: '3rem', flexWrap: 'wrap' }}>
            {[{ num: `${filtered.length}+`, label: 'Events' }, { num: '10K+', label: 'Attendees' }, { num: '50+', label: 'Cities' }].map((s, i) => (
              <div key={i} style={{ textAlign: 'center' }}>
                <p style={{ color: '#e8c4b8', fontWeight: '700', fontSize: '1.4rem', margin: 0 }}>{s.num}</p>
                <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.75rem', margin: 0 }}>{s.label}</p>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* CATEGORY PILLS */}
      <section style={{ background: 'white', padding: '1rem 2rem', borderBottom: '1px solid #f0ddd7', boxShadow: '0 2px 10px rgba(201,169,154,0.1)' }}>
        <div style={{ maxWidth: '1300px', margin: '0 auto', display: 'flex', gap: '8px', overflowX: 'auto', paddingBottom: '2px' }}>
          {CATEGORIES.map(cat => (
            <button key={cat} onClick={() => setCategory(cat)} style={{
              padding: '7px 18px', borderRadius: '20px', border: '1.5px solid',
              cursor: 'pointer', fontWeight: '500', fontSize: '0.8rem', whiteSpace: 'nowrap',
              fontFamily: "'DM Sans', sans-serif", transition: 'all 0.2s',
              borderColor: category === cat ? '#c9a99a' : '#f0ddd7',
              background: category === cat ? 'linear-gradient(135deg, #c9a99a, #e8c4b8)' : 'white',
              color: category === cat ? 'white' : '#8a6a65',
              boxShadow: category === cat ? '0 4px 12px rgba(201,169,154,0.3)' : 'none'
            }}>{cat}</button>
          ))}
        </div>
      </section>

      {/* EVENTS GRID */}
      <section style={{ padding: '3rem 2rem', background: '#fdf6f3' }}>
        <div style={{ maxWidth: '1300px', margin: '0 auto' }}>
          <div style={{ marginBottom: '2rem' }}>
            <h2 style={{ color: '#2d1f1f', fontSize: '1.6rem', fontWeight: '700', margin: 0, fontFamily: "'Cormorant Garamond', serif" }}>
              {category === 'All' ? 'Upcoming Events' : category}
            </h2>
            <p style={{ color: '#a08880', fontSize: '0.83rem', marginTop: '4px' }}>{filtered.length} events found</p>
          </div>

          {loading ? (
            <div style={{ textAlign: 'center', padding: '5rem' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🌸</div>
              <p style={{ color: '#c9a99a' }}>Loading lovely events...</p>
            </div>
          ) : filtered.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '5rem', background: 'white', borderRadius: '20px' }}>
              <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>🌷</div>
              <p style={{ color: '#a08880' }}>No events found. Try different filters.</p>
            </div>
          ) : (
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '1.5rem' }}>
              {filtered.map(event => (
                <div key={event._id} style={{
                  background: 'white', borderRadius: '20px', overflow: 'hidden',
                  boxShadow: '0 4px 20px rgba(201,169,154,0.12)', border: '1px solid #f5e8e3',
                  transition: 'all 0.3s'
                }}
                  onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-5px)'; e.currentTarget.style.boxShadow = '0 16px 40px rgba(201,169,154,0.25)'; }}
                  onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 4px 20px rgba(201,169,154,0.12)'; }}
                >
                  {/* Image */}
                  <div style={{ position: 'relative', height: '190px', overflow: 'hidden' }}>
                    <img
                      src={event.image}
                      alt={event.name}
                      style={{ width: '100%', height: '100%', objectFit: 'cover', transition: 'transform 0.4s' }}
                      onMouseEnter={e => e.target.style.transform = 'scale(1.07)'}
                      onMouseLeave={e => e.target.style.transform = 'scale(1)'}
                      onError={e => { e.target.src = 'https://images.unsplash.com/photo-1470229722913-7c0e2dbbafd3?w=600&q=80'; }}
                    />
                    <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(45,31,31,0.55) 0%, transparent 55%)' }} />
                    {/* Category badge */}
                    <span style={{ position: 'absolute', top: '12px', left: '12px', background: 'rgba(253,246,243,0.92)', backdropFilter: 'blur(10px)', color: '#c9a99a', padding: '4px 12px', borderRadius: '20px', fontSize: '0.7rem', fontWeight: '700' }}>
                      {event.category}
                    </span>
                    {/* Sold out badge */}
                    {event.availableSeats === 0 && (
                      <span style={{ position: 'absolute', top: '12px', right: '12px', background: 'rgba(200,70,70,0.9)', color: 'white', padding: '4px 10px', borderRadius: '20px', fontSize: '0.68rem', fontWeight: '700' }}>SOLD OUT</span>
                    )}
                    {/* Price badge */}
                    <span style={{ position: 'absolute', bottom: '12px', right: '12px', background: 'rgba(253,246,243,0.95)', color: '#c9a99a', padding: '5px 12px', borderRadius: '20px', fontSize: '0.82rem', fontWeight: '800' }}>₹{event.price}</span>
                  </div>

                  {/* Content */}
                  <div style={{ padding: '1.2rem' }}>
                    <h3 style={{ color: '#2d1f1f', fontWeight: '700', fontSize: '0.98rem', marginBottom: '0.5rem', lineHeight: '1.3' }}>{event.name}</h3>
                    <p style={{ color: '#a08880', fontSize: '0.76rem', marginBottom: '0.3rem' }}>📅 {new Date(event.date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })} • {event.time}</p>
                    <p style={{ color: '#a08880', fontSize: '0.76rem', marginBottom: '1rem' }}>📍 {event.venue}</p>

                    {/* Seat progress bar */}
                    <div style={{ marginBottom: '1rem' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                        <span style={{ color: '#c0a0a0', fontSize: '0.68rem' }}>Availability</span>
                        <span style={{ color: '#a08880', fontSize: '0.68rem', fontWeight: '600' }}>{event.availableSeats}/{event.totalSeats}</span>
                      </div>
                      <div style={{ background: '#f5e8e3', borderRadius: '10px', height: '5px', overflow: 'hidden' }}>
                        <div style={{
                          height: '100%', borderRadius: '10px', transition: 'width 0.5s',
                          width: `${event.totalSeats > 0 ? (event.availableSeats / event.totalSeats) * 100 : 0}%`,
                          background: event.availableSeats === 0 ? '#dc6060' : event.availableSeats / event.totalSeats < 0.2 ? '#e8a87c' : 'linear-gradient(90deg, #c9a99a, #e8c4b8)',
                        }} />
                      </div>
                    </div>

                    {/* Book Now Button - fixed to go to event details */}
                    <Link
                      to={isDemo(event._id) ? '/register' : `/events/${event._id}`}
                      style={{
                        display: 'block', textAlign: 'center',
                        background: event.availableSeats === 0 ? '#f5e8e3' : 'linear-gradient(135deg, #c9a99a, #b8887a)',
                        color: event.availableSeats === 0 ? '#c0a0a0' : 'white',
                        padding: '11px', borderRadius: '12px', textDecoration: 'none',
                        fontWeight: '600', fontSize: '0.84rem',
                        pointerEvents: event.availableSeats === 0 ? 'none' : 'auto',
                        boxShadow: event.availableSeats === 0 ? 'none' : '0 4px 14px rgba(201,169,154,0.35)',
                      }}
                    >
                      {event.availableSeats === 0 ? 'Sold Out' : isDemo(event._id) ? '✨ Sign Up to Book' : '🎟️ Book Now'}
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* CTA */}
      <section style={{ background: 'linear-gradient(135deg, #c9a99a 0%, #b8887a 100%)', padding: '5rem 2rem', textAlign: 'center' }}>
        <div style={{ maxWidth: '550px', margin: '0 auto' }}>
          <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🌸</div>
          <h2 style={{ color: 'white', fontSize: '2rem', fontWeight: '700', marginBottom: '0.8rem', fontFamily: "'Cormorant Garamond', serif" }}>Start Your Journey Today</h2>
          <p style={{ color: 'rgba(255,255,255,0.8)', marginBottom: '2rem', fontSize: '0.92rem' }}>Join our community and never miss an amazing event again.</p>
          <Link to="/register" style={{ background: 'white', color: '#c9a99a', padding: '14px 40px', borderRadius: '30px', textDecoration: 'none', fontWeight: '700', fontSize: '0.95rem', display: 'inline-block', boxShadow: '0 8px 25px rgba(45,31,31,0.2)' }}>
            Sign Up Free ✨
          </Link>
        </div>
      </section>
    </div>
  );
}
export default Home;
